import mteb
benchmarks = mteb.get_benchmarks()
scand = None
for b in benchmarks:
    if 'Scandinavian' in b.name:
        scand = b
        break

results = scand.load_results()
print(f'Type: {type(results)}')
print(f'Dir: {[d for d in dir(results) if not d.startswith("_")]}')

# Try to get the leaderboard/ranking
if hasattr(results, 'to_dataframe'):
    df = results.to_dataframe()
    print(df.head(20))
elif hasattr(results, 'get_scores'):
    scores = results.get_scores()
    print(scores)
else:
    # Try various attributes
    for attr in dir(results):
        if not attr.startswith('_'):
            val = getattr(results, attr)
            if not callable(val):
                print(f'{attr}: {type(val)}')
                if isinstance(val, (list, dict)):
                    print(f'  len={len(val)}')
                    if isinstance(val, list) and len(val) > 0:
                        print(f'  first={val[0]}')
                    elif isinstance(val, dict):
                        for k in list(val.keys())[:3]:
                            print(f'  {k}: {val[k]}')
