import urllib.request
import json

# Get the API info
api_url = "https://mteb-leaderboard.hf.space/gradio_api/info"
try:
    req = urllib.request.Request(api_url)
    with urllib.request.urlopen(req, timeout=30) as response:
        data = json.loads(response.read().decode())
        # Print named endpoints
        if 'named_endpoints' in data:
            for name, info in data['named_endpoints'].items():
                print(f"Endpoint: {name}")
                if 'parameters' in info:
                    for p in info['parameters']:
                        print(f"  param: {p.get('parameter_name', '?')} type={p.get('type', '?')}")
        if 'unnamed_endpoints' in data:
            print(f"\nUnnamed endpoints: {len(data['unnamed_endpoints'])}")
            for k,v in list(data['unnamed_endpoints'].items())[:5]:
                print(f"  {k}: {v.get('parameters', [])[:2]}")
except Exception as e:
    print(f"Error: {e}")
PYEOF

