client = Client("mteb/leaderboard")
# Try to call on_benchmark_select - this likely returns the filter options for the selected benchmark
try:
    result = client.predict(api_name="/on_benchmark_select")
    print("Result type:", type(result))
    if isinstance(result, tuple):
        for i, r in enumerate(result):
            print(f"  [{i}]: {type(r)} = {str(r)[:500]}")
    else:
        print(str(result)[:2000])
except Exception as e:
    print(f"Error: {e}")
